mapper.insert:

                    insert into swm_employee_interface (employee_id, work_card, name,
                                            group_id, operation_code, error_msg,
                                            data_status, lump_sum_wage,
                                            post_skill_salary, target_performance_pay,
                                            base_pay, personal_deductibles,
                                            company_deductibles, personal_deduct_accumulation_fund,
                                            company_deduct_accumulation_fund,
                                            high_temperature_subsidy,
                                            safety_accumulation_award,
                                            seniority_allowance,
                                            transportation_allowance,
                                            one_child_subsidy,
                                             post_subsidy,
                                             create_time,
                                            create_by, update_time, update_by)

                    select
ISNULL(
        (
        SELECT
            se.employee_id
        FROM
            swm_employee se
        WHERE
            RIGHT ( cast( '000000' + rtrim( se.work_card ) AS VARCHAR ), 6 ) = RIGHT ( cast( '000000' + rtrim( #{workCard, jdbcType=VARCHAR} ) AS VARCHAR ), 6 )
            and se.name = #{name, jdbcType = VARCHAR}
            AND se.work_flag = 1
            ),- 1
       ),
       #{workCard, jdbcType = VARCHAR}, #{name, jdbcType = VARCHAR}, #{groupId, jdbcType = BIGINT}, 'U',
       CASE WHEN (
        SELECT ISNULL((SELECT se.employee_id FROM swm_employee se WHERE
        RIGHT ( cast( '000000' + rtrim( se.work_card ) AS VARCHAR ), 6 ) = RIGHT ( cast( '000000' + rtrim( #{workCard, jdbcType=VARCHAR} ) AS VARCHAR ), 6 )
        AND se.work_flag = 1 and se.name = #{name, jdbcType = VARCHAR}
        ),- 1)) = - 1 THEN '工号或姓名匹配失败' ELSE '' END,
       CASE WHEN (
        SELECT ISNULL((SELECT se.employee_id FROM swm_employee se WHERE
        RIGHT ( cast( '000000' + rtrim( se.work_card ) AS VARCHAR ), 6 ) = RIGHT ( CAST( '000000' + rtrim( #{workCard, jdbcType=VARCHAR} ) AS VARCHAR ), 6 )
        AND se.work_flag = 1 and se.name = #{name, jdbcType = VARCHAR}
        ),- 1)) = - 1 THEN 'F'
        WHEN EXISTS (
        SELECT 1
          FROM swm_employee se
            WHERE ( 1 = 1

      AND  ISNULL(se.lump_sum_wage, 0) = #{lumpSumWage,jdbcType=DECIMAL}  
      AND  ISNULL(se.post_skill_salary, 0) = #{postSkillSalary,jdbcType=DECIMAL}  
      AND  ISNULL(se.target_performance_pay, 0) = #{targetPerformancePay,jdbcType=DECIMAL}  
      AND  ISNULL(se.base_pay, 0) = #{basePay,jdbcType=DECIMAL}  
      AND  ISNULL(se.personal_deductibles, 0) = #{personalDeductibles,jdbcType=DECIMAL}  
      AND  ISNULL(se.company_deductibles, 0) = #{companyDeductibles,jdbcType=DECIMAL}  
      AND  ISNULL(se.personal_deduct_accumulation_fund, 0) = #{personalDeductAccumulationFund,jdbcType=DECIMAL}  
      AND  ISNULL(se.company_deduct_accumulation_fund, 0) = #{companyDeductAccumulationFund,jdbcType=DECIMAL}  
      AND  ISNULL(se.high_temperature_subsidy, 0) = #{highTemperatureSubsidy,jdbcType=DECIMAL}  
      AND  ISNULL(se.safety_accumulation_award, 0) = #{safetyAccumulationAward,jdbcType=DECIMAL}  
      AND  ISNULL(se.seniority_allowance, 0) = #{seniorityAllowance,jdbcType=DECIMAL}  
      AND  ISNULL(se.transportation_allowance, 0) = #{transportationAllowance,jdbcType=DECIMAL}  
      AND  ISNULL(se.one_child_subsidy, 0) = #{oneChildSubsidy,jdbcType=DECIMAL}  
      AND  ISNULL(se.post_subsidy, 0) = #{postSubsidy,jdbcType=DECIMAL}  )
            AND RIGHT ( cast( '000000' + rtrim( se.work_card ) AS VARCHAR ), 6 ) = RIGHT ( CAST( '000000' + rtrim( #{workCard, jdbcType=VARCHAR} ) AS VARCHAR ), 6 )
        )
        THEN 'W'
        ELSE 'T'
        END,
        #{lumpSumWage,jdbcType=DECIMAL},
        #{postSkillSalary,jdbcType=DECIMAL},
        #{targetPerformancePay,jdbcType=DECIMAL},
        #{basePay,jdbcType=DECIMAL}, #{personalDeductibles,jdbcType=DECIMAL},
        #{companyDeductibles,jdbcType=DECIMAL}, #{personalDeductAccumulationFund,jdbcType=DECIMAL},
        #{companyDeductAccumulationFund,jdbcType=DECIMAL},
        #{highTemperatureSubsidy,jdbcType=DECIMAL}, #{safetyAccumulationAward, jdbcType=DECIMAL}, #{seniorityAllowance, jdbcType=DECIMAL},
        #{transportationAllowance, jdbcType=DECIMAL},#{oneChildSubsidy, jdbcType=DECIMAL}, #{postSubsidy, jdbcType=DECIMAL},
        getdate(),  #{createBy, jdbcType = BIGINT}, getdate(), #{updateBy, jdbcType = BIGINT}
